class Solution:
    def exclusiveTime(self, n, logs):
        res = [0] * n
        stack = []  # (id, accumulated_self_time, start_time)
        for log in logs:
            fid_s, kind, ts_s = log.split(':')
            fid = int(fid_s)
            ts = int(ts_s)
            if kind == 'start':
                stack.append([fid, 0, ts])
            else:
                top = stack.pop()
                elapsed = ts - top[2] + 1
                self_time = elapsed - top[1]
                res[top[0]] += self_time
                if stack:
                    stack[-1][1] += elapsed
        return res

