class Solution:
    def exclusiveTime(self, n, logs):
        res = [0] * n
        stack = []
        prev = 0
        for log in logs:
            fid_s, kind, ts_s = log.split(':')
            fid = int(fid_s)
            ts = int(ts_s)
            if kind == 'start':
                if stack:
                    res[stack[-1]] += ts - prev
                stack.append(fid)
                prev = ts
            else:
                res[stack.pop()] += ts - prev + 1
                prev = ts + 1
        return res

