var exclusiveTime = function(n, logs) {
    const res = new Array(n).fill(0);
    const stack = [];
    let prev = 0;
    for (const log of logs) {
        const [fidS, kind, tsS] = log.split(':');
        const fid = parseInt(fidS, 10);
        const ts = parseInt(tsS, 10);
        if (kind === 'start') {
            if (stack.length) res[stack[stack.length - 1]] += ts - prev;
            stack.push(fid);
            prev = ts;
        } else {
            res[stack.pop()] += ts - prev + 1;
            prev = ts + 1;
        }
    }
    return res;
};
